  ('judicial-de09bf8b-moex-00089', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲不滿被公司資遣，離職前趁仍有公司帳號登入權限之際，將辦公室電腦內儲存之電子郵件悉數 刪除，使得公司業務進行陷入重大困境。關於甲之行為，成立何罪？', '["刑法第359條之無故刪除他人電磁紀錄罪", "刑法第354條毀損財物罪", "刑法第358條入侵他人電腦相關設備罪", "刑法第210條偽變造準私文書罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "559c5671d4e3", "answer_pdf_sha1": "a045179453c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00090', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', 'X 將其 A 畫借給好友 Y，後 X 死亡，其繼承人為甲、乙、丙。因 Y 拒
絕返還 A畫，甲、乙遂為原告，依民法物上請求權之規定向法院訴請 Y
返還 A畫。試說明：
甲、乙提起之訴訟是否具當事人適格？原告應如何表明「應受判決事
項之聲明」？（10 分）
若第一審法院判決原告敗訴，僅甲提起第二審上訴。甲合法提起上訴
後，於第二審言詞辯論終結前甲復具狀表明撤回上訴，其效力及法院
之處理方式為何？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "c7df7548fb31", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00091', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '甲列乙為被告，於民國（下同）113 年 3 月 1 日向管轄法院起訴，求為
判決命乙給付原告 A 畫。原告甲主張之事實及理由略為：甲於 112 年 8
月 1 日將 A畫借予乙，約定借貸期間為六個月，於期間屆滿後，乙至今
拒不交還 A畫，為此，依借用物返還請求權提起本訴。第一審法院審理
後為甲勝訴之本案判決。乙提起上訴，於第二審程序中，A畫因乙之保
管不當而失火燒毀，甲在第二審遂將原訴變更為請求賠償損害新臺幣
（下同）250萬元。試附理由說明：
甲所為之訴之變更有何程序法上之依據？若第二審法院認為甲變更
之新訴有理由，可否為「原判決廢棄，並判命被告給付甲250萬元」
之判決？（13 分）
若第二審法院認為甲變更之新訴有理由，且進行本案審理與言詞辯
論，甲又將原給付聲明由請求給付 250萬元減縮為給付 200萬元。對
此，被告乙表示不同意甲所為 50 萬元之撤回。此減縮或撤回是否適
法？（12分）
20360', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "c7df7548fb31", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00092', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '某夜，A開車見前方員警執行路檢遂急煞減速、臨停路邊紅線，員警見
狀前去盤查要求其搖下車窗，詢問姓名並要求提示身分證明文件（詢問
A）。過程中，員警嗅到 A所駕車內有類似貓尿的怪味，且見副駕駛座 B
匆忙攜身旁手提包即欲下車離去。員警依其多年執勤經驗認為或有使用
安非他命之嫌，故攔阻、壓制 B並詢問該手提包藏有何物（詢問B）。稍
後，員警從中查獲相關毒品一批。試問員警如何進行詢問 A、詢問 B，
方能確保相關不利供述之證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "c7df7548fb31", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00093', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '警察為偵辦毒品犯罪使用 M化偵查網路系統（簡稱「M化車」），追查特
定人犯 A 手機「國際行動設備識別碼」（International Mobile Equipment
Identity）及其 SIM 卡「國際行動用戶識別碼」（International Mobile
SubscriberIdentity），進而確認 A住居所在並查獲毒品一批。試問為確保
查獲毒品之證據能力，警察應如何實施本項蒐證保全？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "c7df7548fb31", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00094', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'essay', '甲乙為好友，甲因公司外派到國外三年，乙剛好需要找屋租賃，甲將其
所有之 A屋在其出國期間借乙住，但借住期間之大樓管理費新臺幣（下
同）30000 元由乙負責，以及水電瓦斯費亦由乙自行負責，乙並幫甲照
顧甲的貓咪，照顧貓咪之相關費用由乙負責。乙住進一個月後，覺得甲
的房子蠻大，在未經甲的同意下以甲的名義，將其中一間房間租給丙，
租期直到甲回國，月租為 6000元，丙應分擔每月的水電與瓦斯費用 500
元。問甲乙丙間之法律關係如何？又甲在國外期間，乙將房間出租取得
收入若干，甲是否得向乙主張享有該出租所得之利益？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00095', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'essay', '甲因個人因素，不便登記為 A屋之所有權人，遂與好友乙約定，將 A屋
登記在乙之名下，但由甲自己使用居住。好友乙因車禍意外死亡，當時
甲因工作旅居義大利，乙的繼承人丙繼承 A屋後，將 A屋賣給不知情的
丁，並將 A屋移轉登記給丁。俟甲回國後，發現丁正在整理 A屋，甲對
丁主張自己是 A屋所有權人，丁則對甲主張自己才是 A屋所有權人，故
請甲清理留置於A屋之物品。請問誰的主張有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00096', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '因侵權行為所生之損害賠償請求權，自請求權人知有損害及賠償義務人時起，幾年間不行使而消 滅？自有侵權行為時起，逾幾年者亦同？ 分別為1年與5年    分別為2年與10年 分別為3年與15年   分別為5年與15年', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00097', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '下列關於消滅時效之敘述，何者正確？ 消滅時效經請求而中斷，所以債權人對於債務人只要不斷請求履行債務，即可達到債權請求權 之時效永遠不完成 消滅時效因起訴而中斷，但若撤回其訴訟，時效視為不中斷 消滅時效經聲請調解而中斷，但若雙方當事人調解不成立，則消滅時效之計算自不成立時，重 新起算 關於無行為能力人對於法定代理人之權利之消滅時效計算，不受法定代理人之代理關係影響', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00098', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-113-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '定期贍養費之請求權消滅時效期間為何？ 1年  2年  5年  15年', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
